const upsertChat = `-- name: UpsertChat :one
INSERT INTO chats (
    id
  , project_id
  , organization_id
  , user_id
  , external_user_id
  , title
  , created_at
  , updated_at
)
VALUES (
    $1,
    $2,
    $3,
    $4,
    $5,
    $6,
    NOW(),
    NOW()
)
ON CONFLICT (id) DO UPDATE SET id = EXCLUDED.id
RETURNING id
`

type UpsertChatParams struct {
	ID             uuid.UUID
	ProjectID      uuid.UUID
	OrganizationID string
	UserID         pgtype.Text
	ExternalUserID pgtype.Text
	Title          pgtype.Text
}

// Use no-op update (id = EXCLUDED.id) to ensure RETURNING always returns a row,
// whether the chat was newly inserted or already existed.
func (q *Queries) UpsertChat(ctx context.Context, arg UpsertChatParams) (uuid.UUID, error) {
	row := q.db.QueryRow(ctx, upsertChat,
		arg.ID,
		arg.ProjectID,
		arg.OrganizationID,
		arg.UserID,
		arg.ExternalUserID,
		arg.Title,
	)
	var id uuid.UUID
	err := row.Scan(&id)
	return id, err
}
